var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이견 없지……? 보내준 기획안.","JPN":"異見ないよね……？　送った企画書。","ENG":"Is there anything you dislike...? The proposal I sent.","TWN":"寄過去的企劃案……沒問題吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"응. 괜찮은 것 같아.","JPN":"うん。大丈夫だと思うわ。","ENG":"No, I think it's all right.","TWN":"嗯，沒問題。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"자세한 건 직접 플레이하면서 확인해 봐야 알 것 같은데…… 다음이 마지막 테스트겠네.","JPN":"詳しいことは直接プレイしながら確認しないとわからないかな……次が最後のテストになりそうね。","ENG":"I'll check the details while I play it myself... but the next test will be the last.","TWN":"詳細內容需要等親自玩過後才能確認……就等下次的最後測試吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"후훗, 다음 테스트도 리네는 안 와주려나?","JPN":"ふふっ、次のテストにもマリちゃんは来てくれないかな？","ENG":"Ha ha. Will Rinae join us for the final test as well?","TWN":"呵呵，下次測試璃奈也不來嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"혹시 리네한테 연락해 봤니?","JPN":"もしかして、マリちゃんに連絡してみた？","ENG":"Did you try contacting her?","TWN":"你有和璃奈連絡過嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"알잖아……. <color=#ffd34c>자유로운 삶</color>……. 리네는.","JPN":"わかるでしょう……<color=#ffd34c>自由な人生</color>……マリって。","ENG":"You know her... <color=#ffd34c>carefree lifestyle</color>... Rinae.","TWN":"璃奈是……<color=#ffd34c>自由的生命</color>……你也知道。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"연락해도 답장…… 많이 늦는 편이고.","JPN":"連絡しても返事……遅いし。","ENG":"Even if I try contacting her... her replies are late.","TWN":"聯絡她……也都回得很慢。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그래야 역시 리네 답지.","JPN":"マリちゃんはそうでなくっちゃね。","ENG":"Well, that's the Rinae we all know.","TWN":"這就是璃奈。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"보라도 많이 바쁘지? 다음에 또 연락할 테니까 오늘은 이만 쉬어.","JPN":"シホちゃんも忙しいでしょう？　また今度連絡するから、今日はもう休んで。","ENG":"You're busy too, right, Bora? I'll call you again later, so you should rest for today.","TWN":"寶拉應該也很忙吧？今天就先這樣，你先休息吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다인아……. 나 할 말이 있는데….","JPN":"タエ……話があるんだけど……","ENG":"Dain... There's something I need to tell you...","TWN":"妲茵……我有話要說…"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"아카데미 강사를 지원하겠다고?","JPN":"アカデミーの講師として志願したい？","ENG":"You want to apply as an instructor for the Academy?","TWN":"你想來當學院的講師？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"혹시…… 무슨 일 있니?","JPN":"もしかして……何かあったの？","ENG":"Did... something happen?","TWN":"發生……什麼事了嗎？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"한 명 있지 않아……? 이번에 새로 임용된 사람.","JPN":"一人いるでしょう……？　今回新しく採用した人。","ENG":"Isn't there a new hire there...? The one who was newly appointed this time.","TWN":"你們最近……是不是有新聘一個人？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"맞아. 분명 이름이…….","JPN":"そうね。確か名前が……","ENG":"Yeah. The name was...","TWN":"有，她叫……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L24_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>가람</color>…… 내 동료.","JPN":"<color=#ffd34c>カワセ・ヒカリ</color>……私の同僚。","ENG":"<color=#ffd34c>Garam</color>... My colleague.","TWN":"<color=#ffd34c>嘉蘭</color>……是我同事。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"지켜봐야 할 것 같아……. 곁에서.","JPN":"見守ってあげないと……そばで。","ENG":"I think I need to look out for her... next to her.","TWN":"我要在一旁……看著。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나도 핵심 개발자니까……. 지원 자격은 충분할 거로 생각해.","JPN":"私もコア開発者だから……志願する資格は十分だと思う。","ENG":"I'm also a core developer, so... I believe I'm qualified to apply.","TWN":"我也是核心製作人……應該有資格。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"역시…… 안 되는 걸까……?","JPN":"やっぱり……ダメかな……？","ENG":"Do you think... I shouldn't...?","TWN":"不行嗎……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"전혀. 자리라면 얼마든지 만들어줄 수 있어.","JPN":"そんなことないわ。職位ならいくらでも用意してあげられる。","ENG":"Not at all. I can give you a position if you want.","TWN":"怎麼會？我可以幫你安排。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"시뮬레이션 강사 자리인데, 어때?","JPN":"シミュレーションの講師なんだけど、どうかしら？","ENG":"The position will be as an instructor for the simulation, is that okay?","TWN":"模擬遊戲的講師怎麼樣？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"좋아……. 자신 있어……. 아마도.","JPN":"いい……自信ある……たぶん。","ENG":"Okay... I can do that... maybe.","TWN":"好……我有信心……應該吧。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"그럼 이날 시간 비워둘게. 편할 때 찾아와줘. \xA0","JPN":"じゃあ、この日に予定を空けておくわね。都合のいい時に来て。\xA0 ","ENG":"Then, I'll book you in for this date. Come see me when it's convenient for you.\xA0","TWN":"那我把這天空下來，你方便時再過來。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……또 전화할게.","JPN":"……また電話する。","ENG":"...I'll call you again later.","TWN":"……再打給你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"너희 셋 다 나중에 크면 일 걱정은 하지 말그래이! 내 한자리씩 다 챙겨줄게!","JPN":"あんたたち三人とも、仕事の心配せんでええよ！　ウチがみんな雇ったる！","ENG":"Now, don't y'all three worry about no jobs, aight? I'll have a position for each of ya!","TWN":"你們三個以後不用怕找不到工作！全都來我公司上班唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"……후훗.","JPN":"……ふふっ。","ENG":"...Ha ha.","TWN":"……呵呵。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L41_1","type":"dialog","speaker":"PRESIDENT_PROMISE_NULL_NPC","text":{"KOREA":"정말…… 미래는 아무도 모르는 일이라니까…….","JPN":"ほんとう……未来は誰にもわからないものね……","ENG":"You were right... No one knows what the future holds...","TWN":"未來的事……真是誰也說不準……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_PROMISE_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"기대되네……. 아카데미.","JPN":"楽しみ……アカデミー。","ENG":"This seems exciting... The Academy.","TWN":"好期待……學院。"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그럼…… 가볼까?","JPN":"じゃあ……行くか。","ENG":"Then... I should get going.","TWN":"那就……出發？"},"stage":{"bg":"OFFICE_DETECT","bgm":"THEMA_GAMECIRCLE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};